import{_ as e,o,c as i,ae as r}from"./chunks/framework.BD9pLfSD.js";const m=JSON.parse('{"title":"xB77: DECLARACIÓN DE MISIÓN","description":"","frontmatter":{},"headers":[],"relativePath":"es/docs/mission.md","filePath":"es/docs/mission.md"}'),n={name:"es/docs/mission.md"};function t(s,a,l,c,d,u){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="xb77-declaracion-de-mision" tabindex="-1">xB77: DECLARACIÓN DE MISIÓN <a class="header-anchor" href="#xb77-declaracion-de-mision" aria-label="Permalink to &quot;xB77: DECLARACIÓN DE MISIÓN&quot;">​</a></h1><h2 id="-la-vision" tabindex="-1"> LA VISIÓN <a class="header-anchor" href="#-la-vision" aria-label="Permalink to &quot; LA VISIÓN&quot;">​</a></h2><p><strong>&quot;La Tarjeta Corporativa Anónima para Agentes AI.&quot;</strong></p><p>xB77 es la infraestructura financiera enfocada en la privacidad que permite a las empresas desplegar agentes autónomos a escala sin exponer sus intereses estratégicos ni los saldos de tesorería al público.</p><hr><h2 id="-el-problema-el-efecto-casa-de-cristal" tabindex="-1"> EL PROBLEMA (El Efecto &quot;Casa de Cristal&quot;) <a class="header-anchor" href="#-el-problema-el-efecto-casa-de-cristal" aria-label="Permalink to &quot; EL PROBLEMA (El Efecto &quot;Casa de Cristal&quot;)&quot;">​</a></h2><p>En el ecosistema Solana actual, cuando una empresa financia agentes AI:</p><ol><li><strong>Exposición de Tesorería:</strong> La competencia puede ver exactamente cuánta liquidez disponible tiene la compañía.</li><li><strong>Filtración de Identidad:</strong> Cada billetera del agente se vincula a la empresa matriz, revelando personal y escala operativa.</li><li><strong>Filtración de Estrategia:</strong> Los patrones de gasto (por ejemplo, adquirir ciertos datasets o GPU) delatan hojas de ruta internas.</li></ol><hr><h2 id="️-la-solucion-la-cuenta-bancaria-fantasma" tabindex="-1">️ LA SOLUCIÓN (LA CUENTA BANCARIA FANTASMA) <a class="header-anchor" href="#️-la-solucion-la-cuenta-bancaria-fantasma" aria-label="Permalink to &quot;️ LA SOLUCIÓN (LA CUENTA BANCARIA FANTASMA)&quot;">​</a></h2><p>xB77 crea una Cuenta Bancaria Fantasma para la economía autónoma que separa la intención estratégica del espacio público:</p><ol><li><strong>La Bóveda (Tesorería Confidencial):</strong> Los fondos están en cuentas Arcium C-SPL; los saldos quedan cifrados y solo los ojos autorizados los conocen.</li><li><strong>La Insignia Fantasma (Identidad ZK):</strong> Los agentes prueban autorización vía Noir sin atar ninguna acción a la tesorería matriz.</li><li><strong>La Caja Negra (Auditoría Comprimida):</strong> Los gastos generan recibos cifrados y comprimidos en Light para que los auditores verifiquen cumplimiento sin exponer los rails.</li></ol><hr><h2 id="️-la-arquitectura-del-mvp-a-produccion" tabindex="-1">️ LA ARQUITECTURA (Del MVP a Producción) <a class="header-anchor" href="#️-la-arquitectura-del-mvp-a-produccion" aria-label="Permalink to &quot;️ LA ARQUITECTURA (Del MVP a Producción)&quot;">​</a></h2><p>xB77 es actualmente una proto-infraestructura funcional diseñada para validar la economía autónoma:</p><ul><li><strong>Plano de Control CFO (Hub):</strong> Monitoreo en tiempo real y visualización forense.</li><li><strong>Pagos Blindados (ShadowWire):</strong> Riel privado B2B desacoplado para transferencias operativas.</li><li><strong>Flujos Ofuscados (Privacy Cash):</strong> Enrutamiento de liquidez que mantiene secretos financieros ocultos.</li><li><strong>Recibos Comprimidos ZK (Light Protocol):</strong> Los auditores ven pruebas; el público no ve nada.</li><li><strong>Gobernanza Humano en el Loop:</strong> Bloqueo automático para acciones de alto riesgo o gatilladas por sanciones.</li></ul><hr><h2 id="-integracion-futura" tabindex="-1"> INTEGRACIÓN FUTURA <a class="header-anchor" href="#-integracion-futura" aria-label="Permalink to &quot; INTEGRACIÓN FUTURA&quot;">​</a></h2><p>Nuestra hoja de ruta incluye vincular esta arquitectura con socios complementarios:</p><ul><li><strong>Kamino Finance (Rendimiento Autónomo):</strong> Agentes autofinanciados que cubren sus propias tarifas vía yield programado.</li><li><strong>Arcium (Estado Confidencial):</strong> Bóvedas cifradas para metadatos sensibles y políticas corporativas.</li><li><strong>Starpay (Puente Fiat):</strong> Financiamiento por tarjeta virtual para on-boarding corporativo heredado.</li></ul><hr><h2 id="-objetivo-del-hackathon" tabindex="-1"> OBJETIVO DEL HACKATHON <a class="header-anchor" href="#-objetivo-del-hackathon" aria-label="Permalink to &quot; OBJETIVO DEL HACKATHON&quot;">​</a></h2><p>Entregar un Sistema Operativo funcional para la Economía de la Sombra de Agentes AI que demuestre que la privacidad es vital para la supervivencia empresarial, arrasando en las pistas Privacy, Arcium y Light Protocol.</p>',23)])])}const g=e(n,[["render",t]]);export{m as __pageData,g as default};
